selector .elementor-image-box-img:before{
    content: "";
    width: 100%;
    height: 100%;
    transition: all ease 0.3s;
    position: absolute;
    margin: auto;
    z-index: 1;
    left: 0;
    top: 0;
    border-radius: 100%;
    box-shadow: 0 0 0 30px #f9f4f0;
}
